import type { CareerQuestion } from "./rrt-questions";

export const himQuestionsBatch6: CareerQuestion[] = [
  { id: "him-453", stem: "Which form is used by institutional providers to submit claims to Medicare?", options: ["UB-04 (CMS-1450)", "CMS-1500", "ADA Dental Claim Form", "CMS-855"], correctIndex: 0, rationale: "The UB-04 (CMS-1450) is the standard claim form used by institutional providers such as hospitals and skilled nursing facilities. CMS-1500 is used by professional/physician providers.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-454", stem: "What is the first step in the revenue cycle?", options: ["Patient scheduling and pre-registration", "Charge capture", "Claims submission", "Payment posting"], correctIndex: 0, rationale: "The revenue cycle begins with scheduling and pre-registration, where patient demographics, insurance information, and eligibility are verified before the encounter occurs.", difficulty: 1, category: "Revenue Cycle Management", topic: "Revenue Cycle Management" },
  { id: "him-455", stem: "Which electronic transaction standard is used for submitting healthcare claims?", options: ["ASC X12 837", "ASC X12 835", "ASC X12 270", "ASC X12 276"], correctIndex: 0, rationale: "The ASC X12 837 transaction set is used for electronic claims submission. The 835 is for remittance advice, 270/271 for eligibility, and 276/277 for claim status.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-456", stem: "A clean claim is defined as:", options: ["A claim that passes all edits and requires no additional information for processing", "A claim with no diagnosis codes", "A claim submitted on paper", "A claim that has been denied and resubmitted"], correctIndex: 0, rationale: "A clean claim contains all required data elements, passes all edits, and can be processed without additional information from the provider, resulting in faster payment.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-457", stem: "What does the chargemaster contain?", options: ["A comprehensive list of all billable items, services, and procedures with associated charges, revenue codes, and CPT/HCPCS codes", "Only surgical procedure codes", "A list of denied claims", "Patient demographic information"], correctIndex: 0, rationale: "The chargemaster (charge description master or CDM) is a comprehensive file containing all services, supplies, and procedures billable to patients with associated charges, revenue codes, CPT/HCPCS codes, and charge amounts.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-458", stem: "Who is primarily responsible for maintaining the chargemaster?", options: ["A multidisciplinary committee including HIM, finance, compliance, and clinical departments", "The billing department alone", "Individual physicians", "The insurance company"], correctIndex: 0, rationale: "Chargemaster maintenance requires a multidisciplinary approach involving HIM professionals, finance, compliance officers, and clinical department representatives to ensure accuracy of codes, descriptions, and charges.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-459", stem: "Which Medicare payment system uses MS-DRGs?", options: ["Inpatient Prospective Payment System (IPPS)", "Outpatient Prospective Payment System (OPPS)", "Resource-Based Relative Value Scale (RBRVS)", "Home Health Prospective Payment System"], correctIndex: 0, rationale: "MS-DRGs (Medicare Severity Diagnosis Related Groups) are used under IPPS to classify inpatient hospital stays into groups for payment purposes based on diagnosis, procedures, age, sex, and discharge status.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-460", stem: "What factor does NOT influence MS-DRG assignment?", options: ["The patient's race or ethnicity", "Principal diagnosis", "Significant procedures performed", "Comorbidities and complications"], correctIndex: 0, rationale: "MS-DRG assignment is based on principal diagnosis, secondary diagnoses (CCs/MCCs), procedures, age, sex, and discharge status. Race and ethnicity are never factors in DRG assignment.", difficulty: 1, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-461", stem: "The DRG grouper software assigns a DRG based on all of the following EXCEPT:", options: ["The patient's insurance premium amount", "Principal diagnosis code", "Procedure codes", "Patient age and sex"], correctIndex: 0, rationale: "The DRG grouper uses clinical and demographic data including diagnoses, procedures, age, sex, and discharge status. Insurance premium amounts are not part of the grouping logic.", difficulty: 1, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-462", stem: "What is a CC in the context of MS-DRGs?", options: ["A complication or comorbidity that increases resource utilization and affects DRG weight", "A chief complaint documented in the record", "A compliance certification", "A claim correction code"], correctIndex: 0, rationale: "In MS-DRGs, a CC (complication or comorbidity) is a secondary diagnosis that increases hospital resource consumption. MCCs (Major CCs) have even greater impact on resource use and reimbursement.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-463", stem: "What is the purpose of the Medicare Code Editor (MCE)?", options: ["To detect errors in ICD-10-CM/PCS coding before DRG assignment", "To assign CPT codes to outpatient visits", "To calculate physician salaries", "To determine patient eligibility for Medicaid"], correctIndex: 0, rationale: "The MCE identifies coding errors such as invalid codes, age/sex conflicts, duplicate codes, and sequencing errors before the DRG grouper assigns the final DRG.", difficulty: 3, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-464", stem: "An MCC designation on a secondary diagnosis will typically:", options: ["Increase the DRG relative weight and reimbursement", "Decrease the DRG relative weight", "Have no effect on reimbursement", "Cause the claim to be denied"], correctIndex: 0, rationale: "Major Complication or Comorbidity (MCC) designations result in assignment to a higher-weighted DRG tier, reflecting greater severity of illness and increased resource consumption, thus increasing reimbursement.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-465", stem: "Which organization developed the DRG classification system?", options: ["Yale University", "Centers for Medicare & Medicaid Services", "American Hospital Association", "Joint Commission"], correctIndex: 0, rationale: "The DRG system was originally developed by researchers at Yale University in the late 1970s. CMS adopted and refined it for use in the Medicare IPPS beginning in 1983.", difficulty: 3, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-466", stem: "What is the purpose of a revenue code on the UB-04?", options: ["To identify the department or type of service where the charge originated", "To specify the patient's diagnosis", "To identify the attending physician", "To report the patient's insurance plan"], correctIndex: 0, rationale: "Revenue codes (e.g., 0250 for pharmacy, 0120 for room and board) identify the specific department or type of service where charges were incurred, required on each line of the UB-04.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-467", stem: "What does accounts receivable (A/R) days measure?", options: ["The average number of days it takes to collect payment after a claim is submitted", "The number of patients admitted per day", "The average length of stay", "The number of denied claims per month"], correctIndex: 0, rationale: "A/R days (also called days in accounts receivable) measures the average time from date of service or claim submission to payment receipt. Lower A/R days indicate more efficient collections.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Cycle Management" },
  { id: "him-468", stem: "A hospital's case mix index (CMI) is 1.85. This means:", options: ["The average DRG relative weight is 1.85, indicating higher-than-average patient acuity", "The hospital has 1.85 beds per patient", "The mortality rate is 1.85%", "The hospital readmission rate is 1.85 times the national average"], correctIndex: 0, rationale: "CMI is the average of all DRG relative weights for a facility. A CMI of 1.85 indicates the hospital treats patients with higher complexity and resource needs compared to a CMI of 1.0.", difficulty: 3, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-469", stem: "Which is an example of a prospective payment system?", options: ["MS-DRGs for inpatient hospital services", "Fee-for-service payment based on individual charges", "Cost-based reimbursement", "Percentage of billed charges"], correctIndex: 0, rationale: "MS-DRGs represent prospective payment where the payment rate is predetermined before services are rendered, based on the patient's diagnosis and procedures rather than actual costs incurred.", difficulty: 1, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-470", stem: "Under the OPPS, services are classified into:", options: ["Ambulatory Payment Classifications (APCs)", "Diagnosis Related Groups (DRGs)", "Resource Utilization Groups (RUGs)", "Case Mix Groups (CMGs)"], correctIndex: 0, rationale: "The Outpatient Prospective Payment System uses APCs to group outpatient services with similar clinical characteristics and resource costs for payment purposes.", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-471", stem: "The Resource-Based Relative Value Scale (RBRVS) is used to determine payment for:", options: ["Physician services under the Medicare Physician Fee Schedule", "Inpatient hospital stays", "Outpatient hospital services", "Skilled nursing facility services"], correctIndex: 0, rationale: "RBRVS assigns relative value units (RVUs) to physician services based on work, practice expense, and malpractice components, forming the basis for the Medicare Physician Fee Schedule.", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-472", stem: "What are the three components of an RVU under RBRVS?", options: ["Work, practice expense, and malpractice", "Diagnosis, procedure, and modifier", "Base rate, outlier, and adjustment", "Fixed, variable, and overhead"], correctIndex: 0, rationale: "Each CPT code has three RVU components: physician work (time, skill, judgment), practice expense (overhead, supplies, staff), and professional liability/malpractice insurance costs.", difficulty: 3, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-473", stem: "What is a capitation payment model?", options: ["A fixed per-member-per-month payment regardless of services provided", "Payment based on each individual service rendered", "A percentage of billed charges", "Payment only when outcomes are achieved"], correctIndex: 0, rationale: "Capitation pays providers a fixed amount per enrolled member per month (PMPM) regardless of whether services are used, shifting financial risk to the provider and incentivizing preventive care.", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-474", stem: "Which reimbursement methodology pays based on actual costs incurred?", options: ["Cost-based reimbursement (retrospective)", "Prospective payment", "Capitation", "Bundled payment"], correctIndex: 0, rationale: "Cost-based (retrospective) reimbursement pays providers based on actual costs incurred in delivering services. This was the predominant method before prospective payment systems were implemented.", difficulty: 1, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-475", stem: "Value-based purchasing (VBP) ties hospital payments to:", options: ["Quality performance measures and patient outcomes", "The number of beds in the facility", "The volume of procedures performed", "The hospital's geographic location only"], correctIndex: 0, rationale: "VBP adjusts Medicare payments based on quality measures including clinical outcomes, patient experience (HCAHPS), safety, and efficiency, rewarding high-performing hospitals.", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-476", stem: "A bundled payment covers:", options: ["All services related to a defined episode of care across providers and settings", "Only the surgeon's fee", "Only the hospital facility charges", "Each individual service separately"], correctIndex: 0, rationale: "Bundled payments (episode-based payments) provide a single payment for all services related to a treatment or condition over a specified period, covering multiple providers and settings.", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-477", stem: "What is the primary purpose of the National Correct Coding Initiative (NCCI)?", options: ["To prevent improper payment of CPT code pairs that should not be reported together", "To assign DRGs to inpatient stays", "To determine patient eligibility", "To calculate physician RVUs"], correctIndex: 0, rationale: "NCCI edits identify pairs of CPT/HCPCS codes that should not be billed together (mutually exclusive or column 1/column 2 edits) to prevent improper payment and promote correct coding.", difficulty: 3, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-478", stem: "Unbundling of codes refers to:", options: ["Billing separately for services that should be reported as a single comprehensive code", "Combining multiple services into one code", "Assigning codes in the correct sequence", "Using ICD-10 instead of ICD-9"], correctIndex: 0, rationale: "Unbundling is the fraudulent practice of billing individual components separately when a single comprehensive code exists, resulting in higher reimbursement than the bundled code would provide.", difficulty: 2, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-479", stem: "The False Claims Act (FCA) prohibits:", options: ["Knowingly submitting false or fraudulent claims to the federal government for payment", "All coding errors regardless of intent", "Use of electronic claims submission", "Physician documentation of medical necessity"], correctIndex: 0, rationale: "The FCA imposes liability on persons and companies that knowingly submit false claims to the government. It includes qui tam provisions allowing whistleblowers to file suits on the government's behalf.", difficulty: 2, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-480", stem: "The Anti-Kickback Statute prohibits:", options: ["Offering, paying, soliciting, or receiving anything of value to induce referrals for services covered by federal healthcare programs", "Negotiating lower prices with suppliers", "Providing charity care to uninsured patients", "Accepting Medicare assignment"], correctIndex: 0, rationale: "The Anti-Kickback Statute (AKS) is a criminal law that prohibits the exchange of anything of value to induce or reward referrals for items or services covered by federal healthcare programs.", difficulty: 3, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-481", stem: "What is the Stark Law?", options: ["A law prohibiting physician self-referral for designated health services to entities with which they have a financial relationship", "A law requiring electronic health records", "A law mandating patient consent for surgery", "A law governing nursing scope of practice"], correctIndex: 0, rationale: "The Physician Self-Referral Law (Stark Law) prohibits physicians from referring Medicare/Medicaid patients for designated health services to entities with which they or immediate family have a financial relationship, unless an exception applies.", difficulty: 3, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-482", stem: "A compliance program should include all of the following EXCEPT:", options: ["Instructions to employees on how to conceal billing errors", "Written policies and procedures", "Designated compliance officer", "Regular auditing and monitoring"], correctIndex: 0, rationale: "An effective compliance program includes written standards, a compliance officer, training, auditing, reporting mechanisms, enforcement, and corrective action. Concealing errors would be a compliance violation.", difficulty: 1, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-483", stem: "An Advance Beneficiary Notice (ABN) is given to a Medicare patient when:", options: ["The provider believes Medicare may not cover a service and wants the patient to accept financial responsibility", "The patient requests a specific medication", "The patient is admitted to the hospital", "The patient changes insurance plans"], correctIndex: 0, rationale: "An ABN (CMS-R-131) is a written notice given to Medicare fee-for-service beneficiaries before they receive items or services that Medicare may not cover, allowing them to make informed decisions about financial responsibility.", difficulty: 2, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-484", stem: "Which federal agency investigates healthcare fraud?", options: ["Office of Inspector General (OIG)", "Centers for Disease Control (CDC)", "Food and Drug Administration (FDA)", "National Institutes of Health (NIH)"], correctIndex: 0, rationale: "The OIG within the Department of Health and Human Services is the primary federal agency responsible for investigating healthcare fraud, waste, and abuse in federal healthcare programs.", difficulty: 1, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-485", stem: "The OIG Work Plan identifies:", options: ["Areas of focus for audits and investigations of healthcare programs", "New CPT codes for the upcoming year", "Hospital accreditation standards", "Medical staff bylaws requirements"], correctIndex: 0, rationale: "The OIG Work Plan outlines specific areas that the OIG intends to investigate in the coming year, helping compliance officers focus their auditing and monitoring activities on high-risk areas.", difficulty: 2, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-486", stem: "What is upcoding?", options: ["Assigning a code that represents a higher level of service or severity than documented", "Using the most specific code available", "Coding from a superbill", "Applying modifier 25 appropriately"], correctIndex: 0, rationale: "Upcoding is the fraudulent practice of assigning codes for more complex, higher-reimbursing services or more severe diagnoses than what is actually documented, constituting false claims.", difficulty: 1, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-487", stem: "Medicare Severity DRGs have how many severity levels?", options: ["Three: without CC/MCC, with CC, and with MCC", "Two: simple and complex", "Four: mild, moderate, severe, critical", "Five: levels 1 through 5"], correctIndex: 0, rationale: "MS-DRGs have three severity tiers: base DRG (without CC/MCC), with CC (complication/comorbidity), and with MCC (major complication/comorbidity), resulting in different payment weights.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-488", stem: "A hospital receives a RAC audit request. RAC stands for:", options: ["Recovery Audit Contractor", "Revenue Accountability Committee", "Reimbursement Assessment Council", "Regulatory Audit Commission"], correctIndex: 0, rationale: "Recovery Audit Contractors identify and correct improper Medicare and Medicaid payments. RACs review claims on a post-payment basis and can identify both overpayments and underpayments.", difficulty: 2, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-489", stem: "What is a charge lag?", options: ["A delay between when a service is provided and when the charge is entered into the billing system", "The difference between charges and payments", "A type of insurance denial", "The time between claim submission and payment"], correctIndex: 0, rationale: "Charge lag occurs when there is a delay in entering charges after services are rendered. This delays billing and can negatively impact cash flow and accounts receivable performance.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Cycle Management" },
  { id: "him-490", stem: "The Medicare Outpatient Code Editor (OCE) performs which function?", options: ["Edits outpatient claims for coding and billing errors before APC assignment", "Assigns MS-DRGs to inpatient claims", "Determines physician fee schedule amounts", "Verifies patient identity"], correctIndex: 0, rationale: "The OCE processes outpatient claims through editing logic to identify errors such as invalid codes, age/sex conflicts, and bundling issues before assigning APCs for payment.", difficulty: 3, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-491", stem: "Which condition code on a UB-04 indicates a patient is a qualified Medicare beneficiary?", options: ["Condition code 04", "Condition code 01", "Condition code 10", "Condition code 44"], correctIndex: 0, rationale: "Condition code 04 indicates the patient is a Qualified Medicare Beneficiary (QMB), meaning Medicaid pays their Medicare premiums and cost-sharing. This affects billing and patient liability.", difficulty: 4, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-492", stem: "A payer denies a claim as a duplicate. The best first step is to:", options: ["Review the original claim to determine if the same service was truly billed twice", "Immediately resubmit the claim", "Write off the balance", "Bill the patient directly"], correctIndex: 0, rationale: "Before taking action on a duplicate denial, review the original claim and the denied claim to determine if it is a true duplicate or if services were distinct and require documentation of the difference.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-493", stem: "What is the timely filing limit for original Medicare claims?", options: ["One calendar year from the date of service", "90 days from the date of service", "180 days from the date of service", "Two years from the date of service"], correctIndex: 0, rationale: "Medicare requires that original claims be submitted within one calendar year (12 months) from the date of service. Claims submitted after this deadline are denied for untimely filing.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-494", stem: "Coordination of Benefits (COB) determines:", options: ["Which insurance plan pays first (primary) and which pays second (secondary) when a patient has multiple coverages", "How much a patient owes in copayments", "Whether a patient qualifies for Medicaid", "The hospital's charge rates"], correctIndex: 0, rationale: "COB rules establish the order of payment responsibility when a patient has coverage under more than one health plan, preventing duplicate payments and ensuring proper billing order.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-495", stem: "Under Medicare Secondary Payer (MSP) rules, Medicare is secondary to:", options: ["Group health plans for working aged beneficiaries with employer coverage", "Medicaid in all situations", "Patient self-pay", "Workers' compensation for non-work-related injuries"], correctIndex: 0, rationale: "MSP rules make Medicare secondary to employer group health plans for working aged (65+) beneficiaries, workers' compensation for work-related injuries, and auto/liability insurance for accident-related care.", difficulty: 3, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-496", stem: "Medicare Part A covers:", options: ["Inpatient hospital, skilled nursing facility, hospice, and home health services", "Physician office visits and outpatient services", "Prescription drugs", "Dental and vision services"], correctIndex: 0, rationale: "Medicare Part A provides coverage for inpatient hospital stays, skilled nursing facility care, hospice services, and some home health services. Part B covers outpatient services and physician visits.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-497", stem: "Medicare Part B covers:", options: ["Physician services, outpatient care, preventive services, and durable medical equipment", "Inpatient hospital stays only", "Prescription drugs at retail pharmacies", "Long-term custodial care"], correctIndex: 0, rationale: "Medicare Part B covers medically necessary outpatient services including physician visits, diagnostic tests, preventive services, DME, and ambulance services. Part D covers prescription drugs.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-498", stem: "A Medicare Advantage plan is classified as:", options: ["Medicare Part C", "Medicare Part A", "Medicare Part B", "Medicare Part D"], correctIndex: 0, rationale: "Medicare Advantage (Part C) plans are offered by private insurance companies approved by Medicare. They must cover all Part A and Part B services and often include Part D drug coverage and additional benefits.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-499", stem: "Medicaid is funded by:", options: ["Both federal and state governments jointly", "The federal government only", "State governments only", "Private insurance premiums only"], correctIndex: 0, rationale: "Medicaid is a joint federal-state program. The federal government provides matching funds (FMAP) to states, with the federal share varying by state based on per capita income.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-500", stem: "A CDI specialist reviews a record and finds documentation of acute respiratory failure with hypoxia but the physician only documented pneumonia. The CDI specialist should:", options: ["Query the physician to clarify if acute respiratory failure is a current condition and its relationship to the pneumonia", "Code acute respiratory failure without a query", "Ignore the clinical indicators", "Wait until after discharge to address the issue"], correctIndex: 0, rationale: "CDI specialists identify clinical indicators suggesting conditions not documented by the physician. A query is needed to confirm the diagnosis and its relationship to other conditions before coding.", difficulty: 3, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-501", stem: "Which clinical indicator would support a query for malnutrition?", options: ["BMI less than 18.5, albumin less than 3.0, unintentional weight loss greater than 10% in 6 months", "Normal albumin with stable weight", "BMI of 25 with no diet modifications", "Hemoglobin A1C of 6.0%"], correctIndex: 0, rationale: "Low BMI, hypoalbuminemia, and significant unintentional weight loss are clinical indicators of malnutrition. CDI programs query for malnutrition documentation as it significantly impacts DRG severity.", difficulty: 3, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-502", stem: "A concurrent CDI review is performed:", options: ["While the patient is still in the hospital", "After the patient has been discharged", "Before the patient is admitted", "Only during coding after discharge"], correctIndex: 0, rationale: "Concurrent CDI reviews occur during the patient's hospitalization, allowing real-time physician queries and documentation improvement while the treating physician can still amend the record.", difficulty: 1, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-503", stem: "Which metric best measures CDI program effectiveness?", options: ["Query response rate and agreement rate, CC/MCC capture rate changes, and CMI impact", "Number of queries sent regardless of outcome", "Total number of charts reviewed", "Number of CDI staff hired"], correctIndex: 0, rationale: "Effective CDI programs track query response rates, physician agreement rates, CC/MCC capture rate improvements, CMI changes, and the impact on quality measures like severity of illness and risk of mortality.", difficulty: 3, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-504", stem: "A retrospective CDI review is performed:", options: ["After the patient has been discharged and the record is complete", "During the patient's hospitalization", "Before the patient is registered", "Only for surgical cases"], correctIndex: 0, rationale: "Retrospective CDI reviews analyze completed records after discharge to identify missed documentation opportunities, track trends, and develop focused education for physicians.", difficulty: 1, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-505", stem: "What is the difference between a leading query and a compliant query?", options: ["A leading query suggests a specific diagnosis; a compliant query presents clinical indicators and asks the physician to determine the diagnosis", "There is no difference between the two", "A leading query is always acceptable in CDI programs", "A compliant query always suggests the highest-paying diagnosis"], correctIndex: 0, rationale: "Leading queries are non-compliant because they direct the physician toward a specific diagnosis. Compliant queries present objective clinical findings and allow the physician to exercise independent clinical judgment.", difficulty: 3, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-506", stem: "Encoder software assists coders by:", options: ["Providing coding logic, references, and guidelines to facilitate accurate code assignment", "Automatically assigning codes without human review", "Replacing the need for clinical documentation", "Eliminating the need for coding education"], correctIndex: 0, rationale: "Encoder software helps coders navigate coding systems through logic trees, cross-references, guidelines, and edits. However, coder expertise is still required for accurate code assignment and review.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-507", stem: "A charge explosion in the chargemaster means:", options: ["A single order automatically generates multiple related charges for component items", "The chargemaster has been deleted", "Charges have increased dramatically", "An error has caused duplicate billing"], correctIndex: 0, rationale: "Charge explosion occurs when a single service order triggers the generation of multiple individual charges for each component (e.g., ordering a CBC may explode into charges for each individual test within the panel).", difficulty: 3, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-508", stem: "Hard-coding in the chargemaster refers to:", options: ["CPT/HCPCS codes permanently linked to chargemaster line items that are automatically included on claims", "Codes assigned manually by coders", "Temporary codes used during system upgrades", "Codes that cannot be changed under any circumstances"], correctIndex: 0, rationale: "Hard-coded items have CPT/HCPCS codes embedded in the chargemaster that automatically populate on claims. Soft-coded items require manual code assignment by HIM coders.", difficulty: 3, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-509", stem: "Soft-coding refers to:", options: ["Codes assigned by HIM coders based on clinical documentation rather than being embedded in the chargemaster", "Codes that are automatically generated by the chargemaster", "Codes used exclusively for outpatient services", "Codes that are always incorrect"], correctIndex: 0, rationale: "Soft-coded procedures require professional review and code assignment by trained HIM coders based on physician documentation, typically for complex services like surgeries and E/M visits.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-510", stem: "A chargemaster review should be performed:", options: ["At least annually, and whenever there are code updates or regulatory changes", "Only when requested by CMS", "Every five years", "Only after an audit finding"], correctIndex: 0, rationale: "Regular chargemaster reviews, at minimum annually, ensure accuracy of codes, descriptions, charges, and revenue codes. Reviews should also occur with annual code updates (CPT, HCPCS, ICD-10) and regulatory changes.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-511", stem: "An outlier payment under IPPS is triggered when:", options: ["The cost of a case exceeds the DRG payment plus a fixed-loss threshold amount", "Every case receives an outlier payment", "The patient stays fewer than 2 days", "The patient is transferred to another facility"], correctIndex: 0, rationale: "Outlier payments provide additional reimbursement for extraordinarily costly cases. They are triggered when the hospital's cost for a case exceeds the DRG payment amount plus a fixed-loss cost threshold set by CMS.", difficulty: 4, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-512", stem: "The wage index adjustment in Medicare payment accounts for:", options: ["Geographic differences in labor costs across hospital markets", "Differences in physician specialty training", "Variations in patient severity", "Hospital profit margins"], correctIndex: 0, rationale: "The wage index adjusts Medicare payments to account for geographic variations in hospital labor costs. Areas with higher labor costs receive higher adjusted payments.", difficulty: 3, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-513", stem: "Disproportionate Share Hospital (DSH) adjustment provides:", options: ["Additional payment to hospitals that serve a disproportionately large number of low-income patients", "Reduced payments for small hospitals", "Higher payments for teaching hospitals only", "Penalties for hospitals with high readmission rates"], correctIndex: 0, rationale: "The DSH adjustment provides additional Medicare payments to hospitals that serve a significantly disproportionate number of low-income patients (Medicaid and Medicare SSI recipients).", difficulty: 3, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-514", stem: "Indirect Medical Education (IME) adjustment provides:", options: ["Additional payment to teaching hospitals to account for the higher costs associated with graduate medical education programs", "Reduced payments to hospitals without residency programs", "Funding for nursing education only", "Tax credits for medical school tuition"], correctIndex: 0, rationale: "The IME adjustment provides additional Medicare IPPS payments to teaching hospitals, recognizing the higher operating costs associated with training medical residents, including increased diagnostic testing and longer lengths of stay.", difficulty: 3, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-515", stem: "The Hospital Readmissions Reduction Program (HRRP) penalizes hospitals for:", options: ["Excess readmissions within 30 days for specified conditions", "High mortality rates", "Long emergency department wait times", "Low patient satisfaction scores only"], correctIndex: 0, rationale: "HRRP reduces payments to hospitals with excess 30-day readmission rates for specified conditions including heart failure, AMI, pneumonia, COPD, hip/knee replacement, and CABG.", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-516", stem: "Hospital-Acquired Condition (HAC) Reduction Program affects payment by:", options: ["Reducing payment by 1% for hospitals in the worst-performing quartile for HACs", "Increasing payment for all hospitals", "Eliminating all HAC-related payments", "Only affecting outpatient payments"], correctIndex: 0, rationale: "The HAC Reduction Program reduces total IPPS payments by 1% for hospitals scoring in the worst-performing 25th percentile for hospital-acquired conditions, incentivizing infection prevention and patient safety.", difficulty: 4, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-517", stem: "A Present on Admission (POA) indicator is used to:", options: ["Identify whether a condition was present at the time of inpatient admission", "Determine the patient's insurance eligibility", "Assign the principal diagnosis", "Calculate the length of stay"], correctIndex: 0, rationale: "POA indicators distinguish conditions present at admission from those that developed during hospitalization. Hospital-acquired conditions not POA may not generate additional DRG payment under CMS rules.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-518", stem: "The POA indicator 'Y' means:", options: ["The condition was present at the time of inpatient admission", "The condition was not present at admission", "The documentation is insufficient to determine POA status", "The condition is exempt from POA reporting"], correctIndex: 0, rationale: "POA indicator Y = present at admission; N = not present at admission; U = documentation insufficient; W = clinically undetermined; Exempt = condition is on the exempt list.", difficulty: 1, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-519", stem: "A transfer DRG applies when:", options: ["A patient is transferred to another acute care facility before the average length of stay for the DRG is met", "A patient is discharged home", "A patient dies during the hospital stay", "A patient is transferred to a long-term care facility in all cases"], correctIndex: 0, rationale: "Transfer DRGs apply per-diem payment methodology when patients are transferred to another acute care hospital before the geometric mean LOS. The transferring hospital receives a per-diem rate rather than the full DRG payment.", difficulty: 4, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-520", stem: "What is the purpose of a Medicare Administrative Contractor (MAC)?", options: ["To process Medicare Part A and Part B claims in assigned jurisdictions", "To set Medicare payment rates nationally", "To develop CPT codes", "To accredit hospitals"], correctIndex: 0, rationale: "MACs are private companies that contract with CMS to process and pay Medicare Part A and Part B claims in specific geographic jurisdictions, handle appeals, and provide provider education.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-521", stem: "A payer mix analysis examines:", options: ["The proportion of patients covered by each type of insurance or payment source", "The number of physicians on the medical staff", "The hospital's square footage", "The types of medical equipment owned"], correctIndex: 0, rationale: "Payer mix analysis identifies the percentage of revenue from each payer source (Medicare, Medicaid, commercial, self-pay). This information is critical for financial planning and contract negotiations.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-522", stem: "Prior authorization is required by many payers to:", options: ["Confirm medical necessity and approve coverage before a service is rendered", "Assign diagnostic codes", "File claims after the service", "Process patient billing statements"], correctIndex: 0, rationale: "Prior authorization (precertification) requires the provider to obtain approval from the payer before performing certain services, ensuring the service meets medical necessity criteria for coverage.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-523", stem: "An Explanation of Benefits (EOB) is sent to:", options: ["The patient, detailing how a claim was processed, what was paid, and what the patient owes", "The provider only", "The government only", "The employer only"], correctIndex: 0, rationale: "The EOB is a statement sent to the patient (or subscriber) by the insurance company explaining how a claim was adjudicated, including amounts billed, allowed, paid, and patient responsibility.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-524", stem: "What is a fee schedule?", options: ["A list of predetermined payment amounts for specific healthcare services", "A hospital admission schedule", "A physician on-call schedule", "A list of patient appointments"], correctIndex: 0, rationale: "A fee schedule is a complete listing of fees used by a payer to reimburse providers for specific services. The Medicare Physician Fee Schedule is an example based on RBRVS.", difficulty: 1, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-525", stem: "Under the per diem payment method, the hospital is paid:", options: ["A fixed rate for each day of hospitalization", "A single amount for the entire stay regardless of length", "Based on individual charges for each service", "Only after the patient is discharged"], correctIndex: 0, rationale: "Per diem reimbursement pays a set dollar amount for each day of hospitalization. Some per diem arrangements use tiered rates (higher for ICU days, lower for med-surg days).", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-526", stem: "What is a contractual adjustment?", options: ["The difference between a provider's billed charges and the amount a payer has agreed to pay under contract", "An increase in patient billing", "A correction to a medical record", "A change in a physician's schedule"], correctIndex: 0, rationale: "Contractual adjustments represent the amount written off as the difference between full charges and the contracted rate with the payer. Providers cannot bill patients for this difference with in-network payers.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Cycle Management" },
  { id: "him-527", stem: "Claim scrubbing software performs which function?", options: ["Reviews claims for errors before submission to payers to improve clean claim rates", "Deletes all claims from the system", "Assigns DRGs to inpatient claims", "Verifies patient identity at registration"], correctIndex: 0, rationale: "Claim scrubbers check claims against coding edits, payer-specific rules, and billing requirements before submission, identifying errors that would cause denials and improving the clean claim rate.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-528", stem: "What is the purpose of a denial management program?", options: ["To systematically track, analyze, and appeal claim denials to maximize appropriate reimbursement", "To deny all incoming patient requests", "To process new patient registrations", "To manage physician referrals"], correctIndex: 0, rationale: "Denial management programs identify denial patterns, implement root cause analysis, manage the appeals process, and develop preventive strategies to reduce future denials and recover lost revenue.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Cycle Management" },
  { id: "him-529", stem: "A clinical validation denial occurs when:", options: ["A payer's physician reviewer disagrees that the clinical evidence supports the coded diagnosis", "A claim is missing the patient's address", "The claim was submitted past the timely filing deadline", "The wrong payer received the claim"], correctIndex: 0, rationale: "Clinical validation denials occur when payer medical directors or clinical reviewers determine that the documentation does not clinically support the coded diagnosis, even if physician documentation states the diagnosis.", difficulty: 4, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-530", stem: "The 72-hour rule (3-day payment window) for Medicare requires:", options: ["Outpatient diagnostic services provided within 72 hours before admission to be included in the inpatient DRG payment", "All patients be discharged within 72 hours", "Claims be submitted within 72 hours", "Payments be made within 72 hours"], correctIndex: 0, rationale: "Medicare's 72-hour rule requires that outpatient diagnostic services (and related non-diagnostic services) provided within the 3 calendar days before an inpatient admission be bundled into the inpatient DRG payment.", difficulty: 4, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-531", stem: "What does the term 'days in A/R' indicate when it is trending upward?", options: ["It is taking longer on average to collect payments, suggesting potential revenue cycle issues", "The hospital is admitting more patients", "Physician productivity is increasing", "Patient satisfaction is improving"], correctIndex: 0, rationale: "Rising days in A/R signals slowing collections, which may indicate problems with claim submission, denials, follow-up, or payer payment delays. Best practice targets are typically 40-50 days or fewer.", difficulty: 3, category: "Revenue Cycle Management", topic: "Revenue Cycle Management" },
  { id: "him-532", stem: "A cost-to-charge ratio (CCR) is used to:", options: ["Convert hospital charges to estimated costs for outlier payment calculations and cost reporting", "Calculate patient copayments", "Determine physician salaries", "Assign ICD-10 codes"], correctIndex: 0, rationale: "The CCR converts billed charges to estimated costs by dividing total costs by total charges. CMS uses department-specific CCRs for outlier payment calculations and cost report analysis.", difficulty: 4, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-533", stem: "The Chargemaster Toolkit reference typically includes:", options: ["Revenue codes, CPT/HCPCS codes, charge amounts, department identifiers, and service descriptions", "Only patient names and addresses", "Physician licensure information", "Insurance company phone numbers"], correctIndex: 0, rationale: "A comprehensive chargemaster entry includes the service description, revenue code, CPT/HCPCS code, charge amount, general ledger key, department number, and activity/status indicators.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-534", stem: "Which type of audit examines coding accuracy on a sample of records?", options: ["A coding compliance audit", "A fire safety audit", "An environmental audit", "A food service audit"], correctIndex: 0, rationale: "Coding compliance audits review a statistically valid sample of coded records to assess accuracy of code assignment, sequencing, and documentation support, identifying education needs and compliance risks.", difficulty: 1, category: "Revenue Cycle Management", topic: "Billing Compliance" },
  { id: "him-535", stem: "Condition code 44 on a UB-04 indicates:", options: ["Inpatient admission changed to outpatient status because the patient did not meet inpatient criteria", "Patient expired during the stay", "Patient left against medical advice", "Patient transferred to another hospital"], correctIndex: 0, rationale: "Condition code 44 is used when a physician concurs with utilization review that an inpatient admission does not meet criteria and the patient's status is changed to outpatient before discharge, requiring rebilling.", difficulty: 4, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-536", stem: "The geometric mean length of stay (GMLOS) for a DRG is used to:", options: ["Calculate transfer per diem payments and identify outlier cases", "Determine physician work RVUs", "Set nurse staffing ratios", "Assign CPT codes"], correctIndex: 0, rationale: "GMLOS is a statistically adjusted average LOS for each DRG. It is used in transfer payment calculations and helps identify cases with unusually long stays for quality review.", difficulty: 4, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-537", stem: "What is a secondary payer?", options: ["The insurance plan that pays after the primary payer has processed the claim", "The patient's employer", "The hospital billing department", "The first insurance billed"], correctIndex: 0, rationale: "The secondary payer processes the claim after the primary payer has adjudicated it. The secondary payer typically pays the remaining covered balance based on its own benefit rules.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-538", stem: "Managed care organizations use which technique to control costs?", options: ["Utilization management including prior authorization, concurrent review, and case management", "Unlimited access to all providers without restriction", "Retrospective payment of all charges without review", "Elimination of all copayments and deductibles"], correctIndex: 0, rationale: "Managed care uses utilization management techniques including prior authorization, concurrent review, discharge planning, case management, and provider networks to control healthcare costs and ensure appropriate care.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-539", stem: "An HMO typically requires:", options: ["Members to select a primary care physician and obtain referrals for specialist care", "No primary care physician selection", "Out-of-network coverage at the same rate as in-network", "No prior authorization for any services"], correctIndex: 0, rationale: "Health Maintenance Organizations typically require members to choose a PCP who serves as a gatekeeper, coordinating care and providing referrals to specialists within the network.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-540", stem: "A PPO differs from an HMO in that:", options: ["PPO members can see out-of-network providers at higher cost-sharing without requiring referrals", "PPOs never cover out-of-network care", "PPOs always require a gatekeeper physician", "PPOs only cover preventive services"], correctIndex: 0, rationale: "Preferred Provider Organizations offer more flexibility than HMOs, allowing members to see any provider but incentivizing in-network use through lower cost-sharing. Referrals are generally not required.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-541", stem: "TRICARE provides healthcare coverage for:", options: ["Active duty military, retirees, and their dependents", "All federal government employees", "Only veterans over age 65", "Medicare beneficiaries exclusively"], correctIndex: 0, rationale: "TRICARE is the healthcare program for uniformed service members (active duty, Guard, Reserve), retirees, and their families, administered by the Defense Health Agency.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-542", stem: "Workers' compensation covers:", options: ["Medical expenses and lost wages for employees injured on the job or with work-related illnesses", "All employee medical expenses regardless of cause", "Only surgical procedures", "Retirement benefits"], correctIndex: 0, rationale: "Workers' compensation is a state-mandated insurance program providing medical treatment, rehabilitation, and wage replacement for employees who sustain work-related injuries or occupational diseases.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-543", stem: "What is a stop-loss provision in insurance?", options: ["A cap on the amount a patient must pay out-of-pocket in a given period", "A limit on the number of claims a provider can submit", "A restriction on the types of services covered", "A prohibition on balance billing"], correctIndex: 0, rationale: "Stop-loss (out-of-pocket maximum) limits the total amount a patient pays for covered services in a benefit period. Once reached, the plan pays 100% of covered services for the remainder of the period.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payer Systems" },
  { id: "him-544", stem: "In CDI, the term 'query rate' refers to:", options: ["The percentage of records reviewed that result in a physician query", "The speed at which physicians respond to queries", "The number of coders employed", "The total number of admissions"], correctIndex: 0, rationale: "Query rate measures CDI program activity by calculating the percentage of reviewed records that generate physician queries. Industry benchmarks typically range from 20-35% depending on facility type.", difficulty: 3, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-545", stem: "Which of the following represents proper query format?", options: ["Open-ended question with clinical indicators and multiple response options including the ability to document a different diagnosis", "A yes/no question asking if the patient has sepsis", "A statement telling the physician which diagnosis to document", "A blank form with no clinical indicators provided"], correctIndex: 0, rationale: "Compliant queries include relevant clinical indicators from the record, present multiple-choice options, allow for alternative diagnoses, and let the physician exercise independent clinical judgment.", difficulty: 3, category: "Revenue Cycle Management", topic: "CDI Programs" },
  { id: "him-546", stem: "Severity of Illness (SOI) and Risk of Mortality (ROM) are determined by:", options: ["APR-DRGs using all-patient refined grouping methodology based on principal diagnosis, secondary diagnoses, procedures, and age", "Only the principal diagnosis code", "Only the length of stay", "Patient self-reported health status"], correctIndex: 0, rationale: "APR-DRGs assign SOI and ROM subclasses (1-4: minor, moderate, major, extreme) based on the interaction of multiple clinical factors, used for quality comparison and risk adjustment.", difficulty: 4, category: "Revenue Cycle Management", topic: "DRG Assignment" },
  { id: "him-547", stem: "A case rate payment methodology pays:", options: ["A single predetermined amount for an entire episode of care regardless of services provided", "Per individual service rendered", "Based on hourly provider time", "A percentage of billed charges for each line item"], correctIndex: 0, rationale: "Case rate (also called flat rate or global payment) provides a single negotiated payment for an entire case, such as a fixed rate for a normal vaginal delivery including all associated services.", difficulty: 2, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-548", stem: "The Merit-based Incentive Payment System (MIPS) affects:", options: ["Medicare physician payments based on quality, cost, improvement activities, and promoting interoperability", "Hospital inpatient DRG payments", "Medicaid managed care rates", "Workers' compensation fee schedules"], correctIndex: 0, rationale: "MIPS adjusts Medicare physician payments based on performance in four categories: quality measures, cost, improvement activities, and promoting interoperability (formerly meaningful use).", difficulty: 3, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-549", stem: "Alternative Payment Models (APMs) differ from fee-for-service by:", options: ["Providing financial incentives for delivering high-quality, cost-efficient care rather than paying based on volume of services", "Paying more for each individual procedure performed", "Eliminating all quality requirements", "Only covering emergency services"], correctIndex: 0, rationale: "APMs move away from volume-based FFS payment by linking financial incentives to quality outcomes and cost efficiency. Examples include ACOs, bundled payments, and patient-centered medical homes.", difficulty: 3, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-550", stem: "An Accountable Care Organization (ACO) is designed to:", options: ["Coordinate care among providers to improve quality while reducing costs, with shared savings for meeting benchmarks", "Operate as a traditional fee-for-service model", "Only provide emergency care services", "Eliminate the need for primary care providers"], correctIndex: 0, rationale: "ACOs are groups of coordinated providers who agree to be accountable for the quality, cost, and experience of care for a defined patient population, sharing in savings achieved below cost benchmarks.", difficulty: 3, category: "Revenue Cycle Management", topic: "Reimbursement Methodologies" },
  { id: "him-551", stem: "A charge capture audit would most likely identify:", options: ["Missing charges for services rendered, incorrect charge codes, and duplicate charges", "Physician credentialing issues", "Nursing staffing ratios", "Patient satisfaction scores"], correctIndex: 0, rationale: "Charge capture audits compare services documented in the medical record with charges posted to identify missed charges (revenue leakage), incorrect charges, duplicate charges, and coding errors.", difficulty: 3, category: "Revenue Cycle Management", topic: "Revenue Cycle Management" },
  { id: "him-552", stem: "The purpose of a compliance hotline in a healthcare organization is to:", options: ["Allow employees to anonymously report suspected fraud, waste, abuse, or compliance violations", "Schedule patient appointments", "Process insurance claims", "Manage physician referrals"], correctIndex: 0, rationale: "A compliance hotline provides a confidential mechanism for employees and others to report suspected compliance violations, fraud, waste, or abuse without fear of retaliation, as required by OIG compliance guidance.", difficulty: 1, category: "Revenue Cycle Management", topic: "Billing Compliance" },
];
